import React, { useEffect } from 'react';
import { motion } from 'framer-motion';

export default function CurtainReveal({ isVisible, onAnimationComplete }) {
  useEffect(() => {
    if (isVisible) {
      console.log('CurtainReveal: Animation started');
      // Call completion callback after animation (1.5s)
      const timer = setTimeout(() => {
        console.log('CurtainReveal: Animation complete');
        onAnimationComplete?.();
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [isVisible, onAnimationComplete]);

  if (!isVisible) {
    console.log('CurtainReveal: Hidden');
    return null;
  }

  console.log('CurtainReveal: Rendering curtains');

  return (
    <>
      {/* LEFT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "-100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '50%',
          height: '100%',
          zIndex: 20,
          background: 'linear-gradient(90deg, #0f1520 0%, #1a2a4a 30%, #2a3a5a 50%, transparent 100%)',
          boxShadow: 'inset -20px 0 40px rgba(212, 175, 55, 0.2), inset -40px 0 60px rgba(0, 0, 0, 0.5)'
        }}
      />

      {/* RIGHT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        style={{
          position: 'fixed',
          top: 0,
          right: 0,
          width: '50%',
          height: '100%',
          zIndex: 20,
          background: 'linear-gradient(270deg, #0f1520 0%, #1a2a4a 30%, #2a3a5a 50%, transparent 100%)',
          boxShadow: 'inset 20px 0 40px rgba(212, 175, 55, 0.2), inset 40px 0 60px rgba(0, 0, 0, 0.5)'
        }}
      />

      {/* LEFT CURTAIN TRIM/DECORATION */}
      <motion.div
        initial={{ x: 0, opacity: 0.8 }}
        animate={{ x: "-100%", opacity: 0.8 }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        style={{
          position: 'fixed',
          top: 0,
          left: '50%',
          transform: 'translateX(-50%)',
          width: '8px',
          height: '100%',
          zIndex: 21,
          background: 'linear-gradient(90deg, transparent 0%, #d4af37 30%, #ffd700 50%, #d4af37 70%, transparent 100%)',
          boxShadow: '0 0 20px rgba(212, 175, 55, 0.6)'
        }}
      />
    </>
  );
}
